def place_rooks(n,k):
    if k == 0:
        return factorial(n)
    filled = n - k
    placements_per_filled = 0
    for i in range(filled):
        mult = 1
        for _ in range(n):
            mult *= (filled-i)
            mult %= 998244353
        placements_per_filled += ((-1)**i)*choose(filled,i)*mult
        placements_per_filled %= 998244353
    total = (2*choose(n,filled)*placements_per_filled ) % 998244353
    if k == 0:
        total//= 2
    return total

