			dp[(i, j, k)] = None

def rec(i, parity, m, a):
	if m < 0:
		return -10000000
	elif dp[(i, parity, m)] is not None:
		return dp[(i, parity, m)]
	else:

		parity += (-1 if a[i]%2==0 else 1)

		if i == len(a)-1:
			if parity == 0:
				return 0
			else:
				return -1000000

		best = rec(i+1, parity, m, a)

		if parity == 0:
			best = max(best, 1 + rec(i+1, 0, m-abs(a[i] - a[i+1]), a))

		dp[(i, parity, m)] = best

		return best




