def bfs(src, S, K):
    from collections import deque

    que = deque([(src)])
    res = set()
    while que:
        s = que.popleft()
        res.add(s)
        if len(res) == K:
            return res
        for i in range(len(s)):
            t = s[:i] + s[i+1:]
            if t in res:
                continue
            que.append(t)
    return res

