def dist(a, b):
    return math.sqrt((a[0] - b[0]) * (a[0] - b[0]) + (a[1] - b[1]) * (a[1] - b[1]))

def samep(a, b):
    EPS = 0.01
    if a - b < -EPS or a - b > EPS:
        return False
    return True

def same(a, b):
    return samep(a[0], b[0]) and samep(a[1], b[1])

def stat(a, tata):
    if tata[a] == a:
        return a
    x = stat(tata[a], tata)
    tata[a] = x
    return x

def unesc(a, b, tata):
    y = stat(b, tata)
    x = stat(a, tata)
    if x != y:
        tata[x] = y
    return

