import sys

def ext_gcd(a, b):
    if b == 0:
        return (a, 1, 0)
    (dp, xp, yp) = ext_gcd(b, a % b)
    return (dp, yp, xp - a//b * yp)

def mod_solve(a, b, n):
    (d, xp, yp) = ext_gcd(a, n)
    if b % d == 0:
        x0 = xp * (b/d) % n
        return x0
    else:
        return None

def choose(n, m, MOD):
    result = 1
    for i in xrange(1, n+1):
        result = (result * i) % MOD
    for i in xrange(1, n-m+1):
        result = (result * mod_solve(i, 1, MOD)) % MOD
    for i in xrange(1, m+1):
        result = (result * mod_solve(i, 1, MOD)) % MOD
    return result

